--
-- Table structure for table `jobs`
--

CREATE TABLE `jobs` (
  `id` varchar(50) NOT NULL,
  `title` varchar(200) NOT NULL,
  `cargoType` enum('Coal','Chrome Ore','Gold Ore','Concentrate','Heavy Equipment','Mining Supplies') NOT NULL,
  `weight` decimal(10,2) NOT NULL DEFAULT 0.00,
  `source` varchar(150) NOT NULL,
  `sourceLat` decimal(10,6) NOT NULL DEFAULT 0.000000,
  `sourceLng` decimal(10,6) NOT NULL DEFAULT 0.000000,
  `destination` varchar(150) NOT NULL,
  `destinationLat` decimal(10,6) NOT NULL DEFAULT 0.000000,
  `destinationLng` decimal(10,6) NOT NULL DEFAULT 0.000000,
  `status` enum('Pending','Assigned','In Transit','Completed') NOT NULL DEFAULT 'Pending',
  `driverId` varchar(50) DEFAULT NULL,
  `truckId` varchar(50) DEFAULT NULL,
  `driverName` varchar(100) DEFAULT NULL,
  `truckPlate` varchar(20) DEFAULT NULL,
  `scheduledDate` varchar(20) DEFAULT NULL,
  `dispatchTime` varchar(20) DEFAULT NULL,
  `completionTime` varchar(20) DEFAULT NULL,
  `estimatedHours` decimal(5,1) NOT NULL DEFAULT 0.0,
  `routeCoordinates` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`routeCoordinates`)),
  `fuelAllocated` decimal(10,2) NOT NULL DEFAULT 0.00,
  `income` decimal(10,2) NOT NULL DEFAULT 0.00,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

